import java.util.Arrays;

public class LinearProbing {
    private static final int EMPTY  = Integer.MIN_VALUE;
    private static final int DELETED = Integer.MIN_VALUE + 1; // tombstone
    private int capacity;
    private int[] keys, vals;

    public LinearProbing(int cap) {
        capacity = cap;
        keys = new int[cap]; vals = new int[cap];
        Arrays.fill(keys, EMPTY);
    }

    private int hash(int key) { return Math.abs(key) % capacity; }

    public void put(int key, int val) {
        int i = hash(key);
        while (keys[i] != EMPTY && keys[i] != DELETED && keys[i] != key)
            i = (i + 1) % capacity; // linear probe
        keys[i] = key; vals[i] = val;
    }

    public int get(int key) {
        int i = hash(key);
        // TODO: probe until EMPTY or key found; skip DELETED slots
        while (keys[i] != EMPTY) {
            if (keys[i] == key) return vals[i];
            // TODO: if DELETED, continue probing
            i = (i + 1) % capacity;
        }
        return -1;
    }

    public void delete(int key) {
        int i = hash(key);
        while (keys[i] != EMPTY) {
            if (keys[i] == key) { keys[i] = DELETED; return; }
            i = (i + 1) % capacity;
        }
    }

    public void printTable() {
        for (int i = 0; i < capacity; i++) {
            String s = keys[i]==EMPTY?"EMPTY":keys[i]==DELETED?"DEL":keys[i]+":"+vals[i];
            System.out.println("[" + i + "] " + s);
        }
    }

    public static void main(String[] args) {
        LinearProbing lp = new LinearProbing(7);
        lp.put(10, 100); lp.put(17, 170); lp.put(24, 240); // 10,17,24 all hash to 3
        lp.put(5, 50);
        lp.printTable();
        System.out.println("get(17): " + lp.get(17));
        lp.delete(17);
        System.out.println("After delete(17), get(24): " + lp.get(24));
    }
}

